class Solution {
    public int wordCount(String[] startWords, String[] targetWords) {
        Set<String> startWordSet = new HashSet<>();
        for (String word : startWords) {
            char[] chars = word.toCharArray();
            Arrays.sort(chars);
            startWordSet.add(new String(chars));
        }

        int count = 0;
        for (String target : targetWords) {
            char[] targetChars = target.toCharArray();
            Arrays.sort(targetChars);
            String targetStr = new String(targetChars);

            boolean found = false;
            for (int i = 0; i < targetStr.length(); i++) {
                String prefix = targetStr.substring(0, i);
                String suffix = targetStr.substring(i);
                if (startWordSet.contains(prefix) && isAppendable(suffix)) {
                    found = true;
                    break;
                }
            }
            if (found) {
                count++;
            }
        }
        return count;
    }

    private boolean isAppendable(String suffix) {
        return suffix.length() == 1 && !Character.isLowerCase(suffix.charAt(0)) ? false : true;
    }
}
